      "content": "const express = require('express');
const { sendError } = require('../../lib/errors');
const service = require('./service');

const router = express.Router();

router.post('/', (req, res) => {
  const { userId, role } = req.body;

  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_PAYLOAD', 'User ID and role are required');
  }

  const member = service.addMember(req.projectId, { userId, role });

  if (member.duplicate) {
    return sendError(res, 409, 'DUPLICATE_MEMBER', 'Member already exists in the project');
  }

  res.status(201).json({ member: member.member });
});

module.exports = router;
